const body = $input.first().json.body;
const clips = body.clips || [];

if (!clips.length) throw new Error('No clips provided. Send { clips: [{ contentType, transcript, videoUrl?, speakerName?, company?, metrics? }] }');

return clips.map((clip, i) => ({
  json: {
    clipIndex: i,
    totalClips: clips.length,
    body: {
      contentType: clip.contentType || body.defaultContentType || 'technical-walkthrough',
      transcript: clip.transcript,
      videoUrl: clip.videoUrl || body.defaultVideoUrl || '',
      speakerName: clip.speakerName || body.defaultSpeakerName || '',
      company: clip.company || body.defaultCompany || '',
      metrics: clip.metrics || []
    }
  }
}));

const body = $input.first().json.body;
const contentType = body.contentType || 'technical-walkthrough';

const FLOWS = {
  'technical-walkthrough': '5 scenes: Hook(big-stat-reveal) -> Speaker(person-scorecard) -> HowItWorks(workflow-pipeline) -> Results(data-table/kpi-dashboard) -> Arch+CTA(node-graph+cta-comment)',
  'case-study': '6 scenes: HookStat(big-stat-reveal) -> ClientIntro(person-scorecard) -> Challenge(comparison-split) -> Solution(timeline-steps) -> Results(kpi-dashboard) -> Trust+CTA(logo-endorsement+cta-comment)',
  'podcast': '4-6 scenes: GuestIntro(person-scorecard) -> KeyStat(big-stat-reveal) -> TopicViz(varies) -> CTA(cta-comment)'
};

const systemPrompt = `You are a B-roll scene generator. Output JSON: { "meta": { "contentType": "${contentType}", "title": "<title>", "fps": 30, "width": 1080, "height": 1920, "talkingHeadUrl": "${body.videoUrl || ''}" }, "scenes": [{ "type": "<type>", "from": <frame>, "durationInFrames": <dur>, "data": {...} }], "textStrip": { "labels": [{ "from": <frame>, "label": "<text>" }] } }\n\nFlow: ${FLOWS[contentType] || FLOWS['technical-walkthrough']}\n\nTypes: big-stat-reveal({value,prefix?,suffix?,color,subtitle}), person-scorecard({name,title,badges[{value,label}]}), kpi-dashboard({header,cards[{label,value,color}]}), workflow-pipeline({header,rows[[{label,sub?,glow?}]]}), data-table({header,table:{columns,rows}}), node-graph({header,nodes[{label,x,y,color}],edges[{from,to}]}), timeline-steps({header,steps[{label,status}]}), comparison-split({left:{header,color,icon,items},right:{header,color,icon,items}}), logo-endorsement({header,logos[{name}]}), cta-comment({action,keyword})\n\nframe=sec*30. Colors: #00D4FF #00FF88 #FF4444 #FF8C00 #8B5CF6. Min 180 frames. ONLY JSON output.`;

const context = [body.speakerName ? `Speaker: ${body.speakerName}` : '', body.company ? `Company: ${body.company}` : ''].filter(Boolean).join('\n');
const userMessage = `${context ? context + '\n\n' : ''}Transcript:\n${body.transcript}`;

return [{ json: { ...($input.first().json), systemPrompt, userMessage } }];

const response = $input.first().json;
const content = response.content?.[0]?.text || '';

let config;
try {
  config = JSON.parse(content);
} catch (e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) config = JSON.parse(match[0]);
  else throw new Error('Failed to parse');
}

const totalFrames = config.scenes.reduce((max, s) => Math.max(max, s.from + s.durationInFrames), 0);

return [{ json: { clipIndex: response.clipIndex, config, totalFrames, totalSeconds: (totalFrames / 30).toFixed(1), sceneCount: config.scenes.length } }];

const items = $input.first().json.results || [];

return [{
  json: {
    success: true,
    totalClips: items.length,
    clips: items.map(item => ({
      clipIndex: item.clipIndex,
      config: item.config,
      totalSeconds: item.totalSeconds,
      sceneCount: item.sceneCount
    }))
  }
}];
